<template>
	<view class="checkout-page">
		<!-- й°ґйГ®ињФеЫЮ + ж†ЗйҐШ -->
		<view class="checkout-header" :style="{ paddingTop: safeAreaInsets.top + 'px' }">
			<view class="header-left" @click="cancelCheckout">
				<text class="back-icon">вАє</text>
			</view>
			<text class="header-title">з°ЃиЃ§иЃҐеНХ</text>
			<view class="header-right"></view>
		</view>

		<!-- еПЦиМґдњ°жБѓ -->
		<view class="block pickup-block">
			<view class="pickup-row">
				<text class="tag">еИ∞еЇЧеПЦ</text>
				<text class="store-name">иіµжЄѓеє≥еНЧдЄ≠ењГиі≠зЙ©еєњеЬЇеЇЧ</text>
				<text class="arrow">></text>
				<text class="distance">2.9km</text>
				<image class="map-icon" src="/static/logo.png" mode="aspectFit" />
			</view>
			<view class="pickup-tip">зО∞еЬ®дЄЛеНХ,йҐДиЃ°7еИЖйТЯеРОеПЦиМґ</view>
		</view>

		<!-- е†Вй£Я/е§ЦеЄ¶ -->
		<view class="block order-type-block">
			<view
				:class="['type-btn', orderType === 'dine' ? 'active' : '']"
				@click="orderType = 'dine'"
			>
				<text class="type-main">е†Вй£Я</text>
				<text class="type-sub">еЇЧеЖЕзО∞еЦЭ</text>
			</view>
			<view
				:class="['type-btn', orderType === 'takeout' ? 'active' : '']"
				@click="orderType = 'takeout'"
			>
				<text class="type-main">е§ЦеЄ¶</text>
				<text class="type-sub">зЇЄиҐЛжЙУеМЕ ></text>
			</view>
		</view>

		<!-- DIY еЦЬиіі -->
		<view class="block diy-block" @click="goDiy">
			<text class="diy-title">DIYеЦЬиіі|йВАдљ†зБµжДЯдЄАзО∞</text>
			<text class="diy-link">еОїеЃЪеИґ ></text>
		</view>

		<!-- еХЖеУБжШОзїЖ -->
		<view class="block product-block">
			<view class="block-title">еХЖеУБжШОзїЖ</view>
			<view class="product-item" v-for="(item, index) in orderItems" :key="index">
				<view class="prod-img-wrap">
					<image :src="item.image || '/static/logo.png'" class="prod-img" mode="aspectFill" />
					<text class="prod-cal" v-if="item.cal">{{ item.cal }} е§ІеН°/жЭѓ</text>
				</view>
				<view class="prod-detail">
					<text class="prod-name">{{ item.name }}</text>
					<text class="prod-spec">{{ item.spec || '' }}</text>
					<view class="prod-right">
						<text class="prod-price">¬•{{ item.price }}</text>
						<text class="prod-num">x{{ item.count }}</text>
					</view>
				</view>
			</view>
		</view>

		<!-- з≤ЊйАЙжР≠йЕН -->
		<view class="block match-block">
			<view class="block-title">з≤ЊйАЙжР≠йЕН</view>
			<scroll-view scroll-x class="match-scroll" show-scrollbar="false">
				<view class="match-item" v-for="(m, i) in matchList" :key="i" @click="addMatch(m)">
					<image :src="m.image || '/static/logo.png'" class="match-img" mode="aspectFill" />
					<text class="match-name">{{ m.name }}</text>
					<text class="match-price">¬•{{ m.price }}</text>
					<view class="match-add">+</view>
				</view>
			</scroll-view>
		</view>

		<!-- дЉШжГ†дњ°жБѓ -->
		<view class="block coupon-block">
			<view class="coupon-card" @click="openCard">
				<view class="coupon-row">
					<text class="coupon-title">еЉАгАМйЗСеЦЬеН°гАНжЬђеНХеПѓеЗП8еЕГ></text>
					<text class="coupon-tag">¬•8.8/90е§©</text>
				</view>
				<text class="coupon-desc">дЇЂ90е§©жЬАйЂШеПѓзЬБ98еЕГ</text>
			</view>
			<view class="coupon-row plain" @click="openCoupon">
				<text class="coupon-label">еЦЬиМґеИЄ</text>
				<text class="coupon-value">жЪВжЧ†еПѓзФ® ></text>
			</view>
		</view>

		<!-- еЇХйГ®жФѓдїШж†П -->
		<view class="bottom-bar">
			<view class="bar-left">
				<text class="bar-label">еЊЕжФѓдїШ</text>
				<text class="bar-price">¬•{{ totalPrice }}</text>
			</view>
			<button class="pay-btn" :class="{ disabled: paying }" @click="doPay" :disabled="paying">
			{{ paying ? 'жФѓдїШдЄ≠...' : 'жФѓдїШ' }}
		</button>
		</view>
	</view>
</template>

<script setup>
import { ref, computed, onMounted } from 'vue';
const { safeAreaInsets } = uni.getSystemInfoSync();

const API_BASE = 'http://localhost:3000';

const orderItems = ref([]);
const orderType = ref('dine');
const paying = ref(false);

const totalPrice = computed(() => {
	return orderItems.value.reduce((sum, it) => sum + it.price * it.count, 0).toFixed(2);
});

const matchList = ref([
	{ id: 1, name: 'иМЙиОЙзїње¶НеЗ§жҐ®...', price: 32.8, image: '' },
	{ id: 2, name: 'зїње¶НиЭіиЭґйЕ•', price: 3.5, image: '' },
	{ id: 3, name: 'йЗСеЗ§иМґйЕ•', price: 1.9, image: '' },
]);

onMounted(() => {
	try {
		const raw = uni.getStorageSync('checkoutOrder');
		if (raw && raw.items && raw.items.length) {
			orderItems.value = raw.items;
			if (raw.orderType) orderType.value = raw.orderType;
			return;
		}
	} catch (e) {}
	orderItems.value = [
		{
			id: 101,
			name: 'е•ЗеЕ∞иЛєжЮЬжЭП(жЧ†жЯ†ж™ђеПґзЙИ)',
			price: 19,
			image: '',
			count: 1,
			spec: 'еЖ∞(жО®иНР),жО®иНР,е∞СзФЬ(жО®иНР),еПѓйЩНиІ£еРЄзЃ°',
			cal: '65',
		},
	];
});

const goDiy = () => {
	uni.showToast({ title: 'еОїеЃЪеИґ', icon: 'none' });
};

const addMatch = () => {
	uni.showToast({ title: 'еЈ≤еК†еЕ•жР≠йЕН', icon: 'none' });
};

const openCard = () => {
	uni.showToast({ title: 'йЗСеЦЬеН°', icon: 'none' });
};

const openCoupon = () => {
	uni.showToast({ title: 'еЦЬиМґеИЄ', icon: 'none' });
};

const cancelCheckout = () => {
	try {
		uni.navigateBack();
	} catch (e) {
		uni.switchTab({ url: '/pages/order/order' });
	}
};

/** е∞Би£Е uni.request дЄЇ Promise */
const request = (options) => {
	return new Promise((resolve, reject) => {
		uni.request({
			...options,
			success: (res) => {
				if (res.statusCode >= 200 && res.statusCode < 300) {
					resolve(res.data);
				} else {
					reject(new Error(res.data?.message || `иѓЈж±Ве§±иі• (${res.statusCode})`));
				}
			},
			fail: (err) => reject(new Error(err.errMsg || 'зљСзїЬйФЩиѓѓ')),
		});
	});
};

/**
 * жФѓдїШжµБз®ЛпЉЪ
 * 1. POST /api/orders        вЖТ еИЫеїЇиЃҐеНХпЉМжЛњеИ∞ orderId
 * 2. POST /api/orders/:id/pay вЖТ ж®°жЛЯжФѓдїШ
 * 3. жИРеКЯеРОж†ЗиЃ∞ justPaidгАБжЄЕйЩ§зїУзЃЧзЉУе≠ШгАБињФеЫЮзВєеНХй°µ
 */
const doPay = async () => {
	if (paying.value) return;
	if (!orderItems.value.length) {
		uni.showToast({ title: 'иЃҐеНХдЄЇз©Ї', icon: 'none' });
		return;
	}

	paying.value = true;
	uni.showLoading({ title: 'ж≠£еЬ®еИЫеїЇиЃҐеНХ...', mask: true });

	try {
		// зђђдЄАж≠•пЉЪеИЫеїЇиЃҐеНХ
		const orderRes = await request({
			url: `${API_BASE}/api/orders`,
			method: 'POST',
			header: { 'Content-Type': 'application/json' },
			data: {
				userId: 1,
				items: orderItems.value,
				orderType: orderType.value,
				totalPrice: Number(totalPrice.value),
			},
		});

		const { orderId, orderNo } = orderRes;
		console.log('[checkout] иЃҐеНХеЈ≤еИЫеїЇ:', orderNo, 'id:', orderId);

		// зђђдЇМж≠•пЉЪж®°жЛЯжФѓдїШ
		uni.showLoading({ title: 'жФѓдїШдЄ≠...', mask: true });
		await request({
			url: `${API_BASE}/api/orders/${orderId}/pay`,
			method: 'POST',
			header: { 'Content-Type': 'application/json' },
		});

		console.log('[checkout] жФѓдїШжИРеКЯ, orderId:', orderId);
		uni.hideLoading();

		// зђђдЄЙж≠•пЉЪжФѓдїШжИРеКЯеРОе§ДзРЖ
		uni.removeStorageSync('checkoutOrder');
		uni.setStorageSync('justPaid', true);
		uni.setStorageSync('lastPaidOrder', {
			orderId,
			orderNo,
			totalPrice: totalPrice.value,
			items: orderItems.value,
			orderType: orderType.value,
			paidAt: new Date().toISOString(),
		});

		uni.showToast({ title: 'жФѓдїШжИРеКЯпЉБ', icon: 'success', duration: 1500 });

		setTimeout(() => {
			uni.switchTab({ url: '/pages/order/order' });
		}, 1500);
	} catch (err) {
		uni.hideLoading();
		console.error('[checkout] жФѓдїШжµБз®ЛеЗЇйФЩ:', err);
		uni.showModal({
			title: 'жФѓдїШе§±иі•',
			content: err.message || 'зљСзїЬеЉВеЄЄпЉМиѓЈз®НеРОйЗНиѓХ',
			showCancel: false,
		});
	} finally {
		paying.value = false;
	}
};
</script>

